"use client";

import { useMemo, useState } from "react";
import { useTheme } from "next-themes";

import { Map, MapControls, MapGeoJSON, MapPopup } from "@/components/ui/map";
import { useWorldData } from "@/lib/use-world-data";
import { mapConfig, visitorsByCountry, type Theme } from "./data";

// WebGL paint can't read CSS variables, so we build a concrete value→color
// expression per theme. The hovered country is highlighted in place via the
// `hover` feature-state, restricted to countries that actually have data.
function buildFillColor(theme: Theme): unknown[] {
  const { base, ramp, hover } = mapConfig.colors[theme];
  const [s0, s1, s2, s3, s4] = mapConfig.scaleStops;
  const ramped = [
    "interpolate",
    ["linear"],
    ["coalesce", ["get", "visitors"], 0],
    s0,
    base,
    s1,
    ramp[0],
    s2,
    ramp[1],
    s3,
    ramp[2],
    s4,
    ramp[3],
  ];
  return [
    "case",
    [
      "all",
      ["boolean", ["feature-state", "hover"], false],
      [">", ["coalesce", ["get", "visitors"], 0], 0],
    ],
    hover,
    ramped,
  ];
}

interface HoverInfo {
  name: string;
  visitors: number;
  lng: number;
  lat: number;
}

interface CountryProperties {
  NAME_LONG: string;
  visitors: number;
}

type CountryFeatureCollection = GeoJSON.FeatureCollection<
  GeoJSON.Geometry,
  CountryProperties
>;

function Legend({ theme }: { theme: Theme }) {
  const gradient = `linear-gradient(to right, ${mapConfig.colors[theme].ramp.join(", ")})`;

  return (
    <div className="bg-card/90 absolute bottom-4 left-4 z-10 rounded-lg border px-3 py-2.5 backdrop-blur-sm">
      <p className="text-foreground text-xs font-medium">Visitors by country</p>
      <div
        className="mt-2 h-2 w-40 rounded-full"
        style={{ backgroundImage: gradient }}
        suppressHydrationWarning
      />
      <div className="text-muted-foreground flex items-center justify-between pt-1.5 text-[10px]">
        <span>Low</span>
        <span>High</span>
      </div>
    </div>
  );
}

export default function Page() {
  const { resolvedTheme } = useTheme();
  const theme: Theme = resolvedTheme === "dark" ? "dark" : "light";
  const [hover, setHover] = useState<HoverInfo | null>(null);
  const world = useWorldData();

  const countries = useMemo<CountryFeatureCollection | null>(() => {
    if (!world) return null;
    return {
      type: "FeatureCollection",
      features: world.features.map((f) => ({
        ...f,
        properties: {
          NAME_LONG: f.properties.NAME_LONG,
          visitors: visitorsByCountry[f.properties.NAME_LONG] ?? 0,
        },
      })),
    };
  }, [world]);

  // Recompute paint only when the theme changes; MapGeoJSON recolors in place.
  const fillPaint = useMemo(
    () => ({
      "fill-color": buildFillColor(theme) as never,
      "fill-opacity": 0.92,
    }),
    [theme],
  );
  return (
    <div className="bg-card relative h-screen overflow-hidden">
      <Map
        blank
        center={mapConfig.view.center}
        zoom={mapConfig.view.zoom}
        minZoom={mapConfig.view.minZoom}
        maxZoom={mapConfig.view.maxZoom}
        dragRotate={false}
        pitchWithRotate={false}
        attributionControl={false}
        loading={!countries}
      >
        {countries && (
          <MapGeoJSON<CountryProperties>
            data={countries}
            promoteId="NAME_LONG"
            fillPaint={fillPaint}
            interactive
            onHover={(e) => {
              const visitors = e?.feature.properties.visitors ?? 0;
              // Only countries with data are interactive.
              if (!e || visitors <= 0) {
                setHover(null);
                return;
              }
              setHover({
                name: e.feature.properties.NAME_LONG,
                visitors,
                lng: e.longitude,
                lat: e.latitude,
              });
            }}
          />
        )}
        <MapControls className="bottom-2" />
        {hover && (
          <MapPopup
            longitude={hover.lng}
            latitude={hover.lat}
            offset={12}
            closeOnClick={false}
            className="pointer-events-none p-2"
          >
            <p className="text-xs font-medium">{hover.name}</p>
            <div className="flex items-center justify-between gap-4 pt-1">
              <span className="text-muted-foreground flex items-center gap-1.5 text-[11px]">
                <span
                  className="size-2 rounded-full"
                  style={{ backgroundColor: mapConfig.colors[theme].hover }}
                />
                Visitors
              </span>
              <span className="text-foreground text-xs font-semibold tabular-nums">
                {hover.visitors.toLocaleString()}
              </span>
            </div>
          </MapPopup>
        )}
      </Map>

      <Legend theme={theme} />
    </div>
  );
}

/** Visitor counts keyed by the feature `NAME_LONG`. */
export const visitorsByCountry: Record<string, number> = {
  Germany: 15,
  "United States": 14,
  "United Kingdom": 12,
  India: 9,
  France: 9,
  Australia: 8,
  Netherlands: 8,
  Spain: 7,
  Italy: 6,
  Sweden: 6,
  Poland: 4,
};

export const MAX_VISITORS = 15;

export type Theme = "light" | "dark";

/** Resolved colors for the choropleth, per theme. */
interface ChoroplethColors {
  /** Fill for countries with no data (value 0). */
  base: string;
  /** Sequential fill ramp from low → high, mapped to `scaleStops`. */
  ramp: [string, string, string, string];
  /** Fill for the hovered country. */
  hover: string;
}

/**
 * Central map config — colors, the value→color scale, and the initial view.
 * WebGL paint can't read CSS variables, so colors are concrete values per
 * theme. The ramp is a single-hue blue scale tuned for contrast on each
 * theme's basemap.
 */
export const mapConfig = {
  view: {
    center: [12, 28] as [number, number],
    zoom: 1.4,
    minZoom: 1,
    maxZoom: 4,
  },
  scaleStops: [0, 1, 5, 10, MAX_VISITORS] as const,
  colors: {
    light: {
      base: "#eef0f3",
      ramp: ["#d4d4d4", "#a3a3a3", "#525252", "#262626"],
      hover: "#0a0a0a",
    },
    dark: {
      base: "#2e2e2e",
      ramp: ["#404040", "#7d7d7d", "#b8b8b8", "#ededed"],
      hover: "#ffffff",
    },
  } satisfies Record<Theme, ChoroplethColors>,
};

"use client";

import { useEffect, useState } from "react";

export const WORLD_GEOJSON =
  "https://cdn.jsdelivr.net/gh/nvkelso/natural-earth-vector@v5.1.2/geojson/ne_110m_admin_0_countries.geojson";

export interface WorldFeatureProperties {
  NAME_LONG: string;
}

export type WorldData = GeoJSON.FeatureCollection<
  GeoJSON.Geometry,
  WorldFeatureProperties
>;

export function useWorldData(url: string = WORLD_GEOJSON): WorldData | null {
  const [data, setData] = useState<WorldData | null>(null);

  useEffect(() => {
    let active = true;
    fetch(url)
      .then((res) => res.json() as Promise<WorldData>)
      .then((world) => {
        if (active) setData(world);
      });
    return () => {
      active = false;
    };
  }, [url]);

  return data;
}
